import json
import logging
import os
import traceback
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import ClientError

# -------------------------------------------------------------------------------------
# Shared Configuration
# -------------------------------------------------------------------------------------

LOG_LEVEL = os.environ.get("LOG_LEVEL", "INFO")
ENVIRONMENT = os.environ.get("ENVIRONMENT", "dev")
AWS_REGION = os.environ.get("AWS_REGION", "us-east-1")
SERVICE_NAME = os.environ.get("SERVICE_NAME", "unknown-service")

# Resource naming convention: all resources prefixed with "microservices-"
# This aligns with the IAM role resource-level permissions above
DYNAMODB_TABLE_PREFIX = "microservices-"
S3_BUCKET_PREFIX = f"{os.environ.get('AWS_ACCOUNT_ID', 'unknown')}-microservices-"
SNS_TOPIC_PREFIX = "microservices-"
SQS_QUEUE_PREFIX = "microservices-"

logger = logging.getLogger(SERVICE_NAME)
logger.setLevel(LOG_LEVEL)


# -------------------------------------------------------------------------------------
# Shared AWS Service Clients (lazy initialization)
# -------------------------------------------------------------------------------------

class AWSClients:
    """Singleton-style lazy-initialized AWS clients shared across invocations."""

    _s3_client = None
    _dynamodb_resource = None
    _sns_client = None
    _sqs_client = None

    @classmethod
    def s3(cls):
        if cls._s3_client is None:
            cls._s3_client = boto3.client("s3", region_name=AWS_REGION)
        return cls._s3_client

    @classmethod
    def dynamodb(cls):
        if cls._dynamodb_resource is None:
            cls._dynamodb_resource = boto3.resource("dynamodb", region_name=AWS_REGION)
        return cls._dynamodb_resource

    @classmethod
    def dynamodb_table(cls, table_short_name: str):
        full_name = f"{DYNAMODB_TABLE_PREFIX}{table_short_name}"
        return cls.dynamodb().Table(full_name)

    @classmethod
    def sns(cls):
        if cls._sns_client is None:
            cls._sns_client = boto3.client("sns", region_name=AWS_REGION)
        return cls._sns_client

    @classmethod
    def sqs(cls):
        if cls._sqs_client is None:
            cls._sqs_client = boto3.client("sqs", region_name=AWS_REGION)
        return cls._sqs_client


# -------------------------------------------------------------------------------------
# Shared Response Builder
# -------------------------------------------------------------------------------------

def build_response(status_code: int, body: Any, headers: Optional[Dict] = None) -> Dict:
    """Build a standardized API Gateway response."""
    default_headers = {
        "Content-Type": "application/json",
        "X-Service-Name": SERVICE_NAME,
        "X-Environment": ENVIRONMENT,
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type,Authorization",
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str),
    }


# -------------------------------------------------------------------------------------
# Shared Lambda Decorator (error handling, logging, metrics)
# -------------------------------------------------------------------------------------

def lambda_middleware(func):
    """Decorator providing consistent error handling, logging, and structure."""

    @wraps(func)
    def wrapper(event, context):
        request_id = getattr(context, "aws_request_id", "unknown")
        function_name = getattr(context, "function_name", "unknown")

        logger.info(
            json.dumps({
                "message": "Lambda invocation started",
                "request_id": request_id,
                "function_name": function_name,
                "service": SERVICE_NAME,
                "event_source": _detect_event_source(event),
            })
        )

        try:
            result = func(event, context)

            logger.info(
                json.dumps({
                    "message": "Lambda invocation completed",
                    "request_id": request_id,
                    "function_name": function_name,
                    "status": "success",
                })
            )
            return result

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(
                json.dumps({
                    "message": "AWS ClientError",
                    "request_id": request_id,
                    "error_code": error_code,
                    "error_message": error_message,
                    "traceback": traceback.format_exc(),
                })
            )
            return build_response(500, {
                "error": "Internal service error",
                "error_code": error_code,
                "request_id": request_id,
            })

        except ValueError as e:
            logger.warning(
                json.dumps({
                    "message": "Validation error",
                    "request_id": request_id,
                    "error": str(e),
                })
            )
            return build_response(400, {
                "error": "Bad request",
                "message": str(e),
                "request_id": request_id,
            })

        except Exception as e:
            logger.error(
                json.dumps({
                    "message": "Unhandled exception",
                    "request_id": request_id,
                    "error": str(e),
                    "traceback": traceback.format_exc(),
                })
            )
            return build_response(500, {
                "error": "Internal server error",
                "request_id": request_id,
            })

    return wrapper


def _detect_event_source(event: Dict) -> str:
    """Detect the source of the Lambda invocation."""
    if "Records" in event:
        records = event["Records"]
        if records:
            source = records[0].get("eventSource", records[0].get("EventSource", ""))
            if "sqs" in source.lower():
                return "sqs"
            if "sns" in source.lower():
                return "sns"
            if "s3" in source.lower():
                return "s3"
            if "dynamodb" in source.lower():
                return "dynamodb_stream"
    if "httpMethod" in event or "requestContext" in event:
        return "api_gateway"
    if "detail-type" in event:
        return "eventbridge"
    if "source" in event and event.get("source") == "aws.events":
        return "scheduled_event"
    return "direct_invocation"


# -------------------------------------------------------------------------------------
# Shared Helper Utilities for Common AWS Operations
# -------------------------------------------------------------------------------------

class DynamoDBHelper:
    """Helper methods for DynamoDB operations using the shared IAM role."""

    @staticmethod
    def get_item(table_name: str, key: Dict) -> Optional[Dict]:
        table = AWSClients.dynamodb_table(table_name)
        response = table.get_item(Key=key)
        return response.get("Item")

    @staticmethod
    def put_item(table_name: str, item: Dict) -> Dict:
        item["updated_at"] = datetime.now(timezone.utc).isoformat()
        if "created_at" not in item:
            item["created_at"] = item["updated_at"]
        table = AWSClients.dynamodb_table(table_name)
        return table.put_item(Item=item)

    @staticmethod
    def update_item(table_name: str, key: Dict, updates: Dict) -> Dict:
        update_expr_parts = []
        expr_attr_names = {}
        expr_attr_values = {}

        updates["updated_at"] = datetime.now(timezone.utc).isoformat()

        for i, (attr, value) in enumerate(updates.items()):
            placeholder_name = f"#attr{i}"
            placeholder_value = f":val{i}"
            update_expr_parts.append(f"{placeholder_name} = {placeholder_value}")
            expr_attr_names[placeholder_name] = attr
            expr_attr_values[placeholder_value] = value

        table = AWSClients.dynamodb_table(table_name)
        return table.update_item(
            Key=key,
            UpdateExpression="SET " + ", ".join(update_expr_parts),
            ExpressionAttributeNames=expr_attr_names,
            ExpressionAttributeValues=expr_attr_values,
            ReturnValues="ALL_NEW",
        )

    @staticmethod
    def delete_item(table_name: str, key: Dict) -> Dict:
        table = AWSClients.dynamodb_table(table_name)
        return table.delete_item(Key=key, ReturnValues="ALL_OLD")

    @staticmethod
    def query(table_name: str, key_condition_expression, **kwargs) -> list:
        table = AWSClients.dynamodb_table(table_name)
        items = []
        response = table.query(KeyConditionExpression=key_condition_expression, **kwargs)
        items.extend(response.get("Items", []))
        while "LastEvaluatedKey" in response:
            response = table.query(
                KeyConditionExpression=key_condition_expression,
                ExclusiveStartKey=response["LastEvaluatedKey"],
                **kwargs,
            )
            items.extend(response.get("Items", []))
        return items


class S3Helper:
    """Helper methods for S3 operations using the shared IAM role."""

    @staticmethod
    def get_object(bucket_name: str, key: str) -> bytes:
        response = AWSClients.s3().get_object(Bucket=bucket_name, Key=key)
        return response["Body"].read()

    @staticmethod
    def get_json(bucket_name: str, key: str) -> Dict:
        data = S3Helper.get_object(bucket_name, key)
        return json.loads(data)

    @staticmethod
    def put_object(bucket_name: str, key: str, body: bytes, content_type: str = "application/octet-stream") -> Dict:
        return AWSClients.s3().put_object(
            Bucket=bucket_name,
            Key=key,
            Body=body,
            ContentType=content_type,
        )

    @staticmethod
    def put_json(bucket_name: str, key: str, data: Dict) -> Dict:
        return S3Helper.put_object(
            bucket_name, key, json.dumps(data, default=str).encode("utf-8"), "application/json"
        )

    @staticmethod
    def delete_object(bucket_name: str, key: str) -> Dict:
        return AWSClients.s3().delete_object(Bucket=bucket_name, Key=key)

    @staticmethod
    def list_objects(bucket_name: str, prefix: str = "") -> list:
        objects = []
        paginator = AWSClients.s3().get_paginator("list_objects_v2")
        for page in paginator.paginate(Bucket=bucket_name, Prefix=prefix):
            objects.extend(page.get("Contents", []))
        return objects


class SNSHelper:
    """Helper methods for SNS operations using the shared IAM role."""

    @staticmethod
    def publish(topic_short_name: str, message: Dict, subject: Optional[str] = None,
                message_attributes: Optional[Dict] = None) -> Dict:
        account_id = os.environ.get("AWS_ACCOUNT_ID", "")
        topic_arn = f"arn:aws:sns:{AWS_REGION}:{account_id}:{SNS_TOPIC_PREFIX}{topic_short_name}"

        params = {
            "TopicArn": topic_arn,
            "Message": json.dumps(message, default=str),
        }
        if subject:
            params["Subject"] = subject
        if message_attributes:
            params["MessageAttributes"] = message_attributes

        return AWSClients.sns().publish(**params)


class SQSHelper:
    """Helper methods for SQS operations using the shared IAM role."""

    _queue_url_cache = {}

    @classmethod
    def _get_queue_url(cls, queue_short_name: str) -> str:
        full_name = f"{SQS_QUEUE_PREFIX}{queue_short_name}"
        if full_name not in cls._queue_url_cache:
            response = AWSClients.sqs().get_queue_url(QueueName=full_name)
            cls._queue_url_cache[full_name] = response["QueueUrl"]
        return cls._queue_url_cache[full_name]

    @classmethod
    def send_message(cls, queue_short_name: str, message: Dict,
                     delay_seconds: int = 0, message_attributes: Optional[Dict] = None) -> Dict:
        queue_url = cls._get_queue_url(queue_short_name)
        params = {
            "QueueUrl": queue_url,
            "MessageBody": json.dumps(message, default=str),
            "DelaySeconds": delay_seconds,
        }
        if message_attributes:
            params["MessageAttributes"] = message_attributes
        return AWSClients.sqs().send_message(**params)

    @classmethod
    def delete_message(cls, queue_short_name: str, receipt_handle: str) -> Dict:
        queue_url = cls._get_queue_url(queue_short_name)
        return AWSClients.sqs().delete_message(
            QueueUrl=queue_url,
            ReceiptHandle=receipt_handle,
        )


# -------------------------------------------------------------------------------------
# Example Lambda Function #1: Order Processor (API Gateway triggered)
# -------------------------------------------------------------------------------------
# This function demonstrates an API Gateway-triggered Lambda that processes orders.
# It uses the SAME shared IAM role as all other functions.

ORDER_TABLE = "orders"
ORDER_NOTIFICATION_TOPIC = "order-events"
ORDER_PROCESSING_QUEUE = "order-processing"


@lambda_middleware
def order_processor_handler(event, context):
    """
    Handles order CRUD operations via API Gateway.
    Deployed with: Role: !ImportValue shared-microservices-lambda-role-arn
    """
    http_method = event.get("httpMethod", "GET")
    path_params = event.get("pathParameters") or {}
    body = json.loads(event.get("body") or "{}") if event.get("body") else {}

    if http_method == "POST":
        return _create_order(body)
    elif http_method == "GET" and "order_id" in path_params:
        return _get_order(path_params["order_id"])
    elif http_method == "PUT" and "order_id" in path_params:
        return _update_order(path_params["order_id"], body)
    elif http_method == "DELETE" and "order_id" in path_params:
        return _delete_order(path_params["order_id"])
    else:
        return build_response(405, {"error": "Method not allowed"})


def _create_order(body: Dict) -> Dict:
    required_fields = ["customer_id", "items", "total_amount"]
    for field in required_fields:
        if field not in body:
            raise ValueError(f"Missing required field: {field}")

    import uuid
    order_id = str(uuid.uuid4())

    order = {
        "order_id": order_id,
        "customer_id": body["customer_id"],
        "items": body["items"],
        "total_amount": str(body["total_amount"]),
        "status": "pending",
        "environment": ENVIRONMENT,
    }

    # Save to DynamoDB
    DynamoDBHelper.put_item(ORDER_TABLE, order)

    # Publish event to SNS
    SNSHelper.publish(ORDER_NOTIFICATION_TOPIC, {
        "event_type": "ORDER_CREATED",
        "order_id": order_id,
        "customer_id": body["customer_id"],
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }, subject="Order Created")

    # Queue for async processing
    SQSHelper.send_message(ORDER_PROCESSING_QUEUE, {
        "action": "process_new_order",
        "order_id": order_id,
    })

    logger.info(f"Order created: {order_id}")
    return build_response(201, {"message": "Order created", "order_id": order_id})


def _get_order(order_id: str) -> Dict:
    order = DynamoDBHelper.get_item(ORDER_TABLE, {"order_id": order_id})
    if not order:
        return build_response(404, {"error": "Order not found"})
    return build_response(200, order)


def _update_order(order_id: str, body: Dict) -> Dict:
    existing = DynamoDBHelper.get_item(ORDER_TABLE, {"order_id": order_id})
    if not existing:
        return build_response(404, {"error": "Order not found"})

    allowed_updates = {k: v for k, v in body.items() if k in ["status", "items", "total_amount"]}
    if not allowed_updates:
        raise ValueError("No valid fields to update")

    if "total_amount" in allowed_updates:
        allowed_updates["total_amount"] = str(allowed_updates["total_amount"])

    result = DynamoDBHelper.update_item(ORDER_TABLE, {"order_id": order_id}, allowed_updates)

    SNSHelper.publish(ORDER_NOTIFICATION_TOPIC, {
        "event_type": "ORDER_UPDATED",
        "order_id": order_id,
        "updated_fields": list(allowed_updates.keys()),
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }, subject="Order Updated")

    return build_response(200, {"message": "Order updated", "order": result.get("Attributes", {})})


def _delete_order(order_id: str) -> Dict:
    result = DynamoDBHelper.delete_item(ORDER_TABLE, {"order_id": order_id})
    if not result.get("Attributes"):
        return build_response(404, {"error": "Order not found"})

    SNSHelper.publish(ORDER_NOTIFICATION_TOPIC, {
        "event_type": "ORDER_DELETED",
        "order_id": order_id,
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }, subject="Order Deleted")

    return build_response(200, {"message": "Order deleted"})


# -------------------------------------------------------------------------------------
# Example Lambda Function #2: SQS Queue Processor
# -------------------------------------------------------------------------------------
# Another function sharing the SAME IAM role.

INVENTORY_TABLE = "inventory"
FULFILLMENT_QUEUE = "fulfillment"


@lambda_middleware
def queue_processor_handler(event, context):
    """
    Processes messages from SQS queues.
    Deployed with: Role: !ImportValue shared-microservices-lambda-role-arn
    """
    records = event.get("Records", [])
    failed_message_ids = []

    for record in records:
        message_id = record.get("messageId", "unknown")
        try:
            body = json.loads(record["body"])
            action = body.get("action", "")

            if action == "process_new_order":
                _process_new_order(body)
            elif action == "update_inventory":
                _update_inventory(body)
            else:
                logger.warning(f"Unknown action: {action} for message {message_id}")

        except Exception as e:
            logger.error(f"Failed to process message {message_id}: {str(e)}")
            failed_message_ids.append(message_id)

    # Return failures for SQS partial batch response
    if failed_message_ids:
        return {
            "batchItemFailures": [
                {"itemIdentifier": mid} for mid in failed_message_ids
            ]
        }

    return {"batchItemFailures": []}


def _process_new_order(body: Dict):
    order_id = body["order_id"]
    order = DynamoDBHelper.get_item(ORDER_TABLE, {"order_id": order_id})
    if not order:
        logger.error(f"Order {order_id} not found for processing")
        return

    # Update order status
    DynamoDBHelper.update_item(ORDER_TABLE, {"order_id": order_id}, {"status": "processing"})

    # Store processing record in S3
    bucket = f"{S3_BUCKET_PREFIX}processing-logs"
    key = f"orders/{order_id}/processing-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}.json"
    S3Helper.put_json(bucket, key, {
        "order_id": order_id,
        "status": "processing_started",
        "timestamp": datetime.now(timezone.utc).isoformat(),
    })

    # Queue for fulfillment
    SQSHelper.send_message(FULFILLMENT_QUEUE, {
        "action": "fulfill_order",
        "order_id": order_id,
        "items": order.get("items", []),
    })

    logger.info(f"Order {order_id} sent to fulfillment")


def _update_inventory(body: Dict):
    product_id = body.get("product_id")
    quantity_change = body.get("quantity_change", 0)
    if not product_id:
        raise ValueError("Missing product_id for inventory update")

    DynamoDBHelper.update_item(
        INVENTORY_TABLE,
        {"product_id": product_id},
        {"last_quantity_change": str(quantity_change)},
    )
    logger.info(f"Inventory updated for product {product_id}: {quantity_change}")


# -------------------------------------------------------------------------------------
# Example Lambda Function #3: S3 Event Processor
# -------------------------------------------------------------------------------------

REPORT_TABLE = "reports"
REPORT_NOTIFICATION_TOPIC = "report-events"


@lambda_middleware
def s3_event_processor_handler(event, context):
    """
    Processes S3 events (e.g., file uploads).
    Deployed with: Role: !ImportValue shared-microservices-lambda-role-arn
    """
    records = event.get("Records", [])
    processed_count = 0

    for record in records:
        s3_info = record.get("s3", {})
        bucket_name = s3_info.get("bucket", {}).get("name", "")
        object_key = s3_info.get("object", {}).get("key", "")
        event_name = record.get("eventName", "")

        logger.info(f"Processing S3 event: {event_name} for {bucket_name}/{object_key}")

        if object_key.endswith(".json") and "uploads/" in object_key:
            data = S3Helper.get_json(bucket_name, object_key)

            import uuid
            report_id = str(uuid.uuid4())

            DynamoDBHelper.put_item(REPORT_TABLE, {
                "report_id": report_id,
                "source_bucket": bucket_name,
                "source_key": object_key,
                "status": "processed",
                "record_count": len(data) if isinstance(data, list) else 1,
            })

            SNSHelper.publish(REPORT_NOTIFICATION_TOPIC, {
                "event_type": "REPORT_PROCESSED",
                "report_id": report_id,
                "source": f"s3://{bucket_name}/{object_key}",
                "timestamp": datetime.now(timezone.utc).isoformat(),
            }, subject="Report Processed")

            processed_count += 1

    return {"processed_count": processed_count}


