# Lambda Handler Entry Points
# -------------------------------------------------------------------------------------
# Each of these would be a separate Lambda function in deployment,
# ALL sharing the same IAM role: shared-microservices-lambda-role
#
# SAM template example:
#
#   OrderProcessorFunction:
#     Type: AWS::Serverless::Function
#     Properties:
#       Handler: shared_iam_role.order_processor_handler
#       Role: !ImportValue shared-microservices-lambda-role-arn
#       Runtime: python3.12
#       Timeout: 30
#       MemorySize: 256
#       Environment:
#         Variables:
#           SERVICE_NAME: order-processor
#           ENVIRONMENT: !Ref Environment
#           AWS_ACCOUNT_ID: !Ref AWS::AccountId
#
#   QueueProcessorFunction:
#     Type: AWS::Serverless::Function
#     Properties:
#       Handler: shared_iam_role.queue_processor_handler
#       Role: !ImportValue shared-microservices-lambda-role-arn
#       Runtime: python3.12
#       Timeout: 60
#       MemorySize: 256
#       Events:
#         OrderProcessingQueue:
#           Type: SQS
#           Properties:
#             Queue: !GetAtt OrderProcessingQueue.Arn
#             BatchSize: 10
#             FunctionResponseTypes:
#               - ReportBatchItemFailures
#
#   S3EventProcessorFunction:
#     Type: AWS::Serverless::Function
#     Properties:
#       Handler: shared_iam_role.s3_event_processor_handler
#       Role: !ImportValue shared-microservices-lambda-role-arn
#       Runtime: python3.12
#       Timeout: 60
#       MemorySize: 512
#
# -------------------------------------------------------------------------------------

# Expose handlers at module level
lambda_handler = order_processor_handler  # Default handler